  1→//! BenchmarkRunner — constructs Claude CLI commands with specialist prompts,
  2→//! executes them as async subprocesses, and parses JSON output into structured results.
  3→
  4→use anyhow::{Context, Result};
  5→
  6→use super::scorer::Finding;
  7→use forge::autoresearch::benchmarks::BenchmarkCase;
  8→
  9→/// The result of running a specialist against one benchmark case.
 10→#[derive(Debug, Clone)]
 11→pub struct BenchmarkResult {
 12→    pub case_name: String,
 13→    pub verdict: String,
 14→    pub findings: Vec<Finding>,
 15→    pub raw_output: String,
 16→    pub error: Option<String>,
 17→}
 18→
 19→/// A constructed CLI command for test inspection without execution.
 20→#[derive(Debug, Clone)]
 21→pub struct ConstructedCommand {
 22→    pub program: String,
 23→    pub args: Vec<String>,
 24→}
 25→
 26→/// Runs specialist prompts against benchmark cases via the Claude CLI.
 27→pub struct BenchmarkRunner {
 28→    claude_cmd: String,
 29→}
 30→
 31→impl BenchmarkRunner {
 32→    /// Create a new runner with the given Claude CLI command.
 33→    pub fn new(claude_cmd: String) -> Self {
 34→        Self { claude_cmd }
 35→    }
 36→
 37→    /// Build a review prompt combining specialist instructions, code, context, and output format.
 38→    pub fn build_review_prompt(
 39→        &self,
 40→        specialist_prompt: &str,
 41→        code: &str,
 42→        context: &str,
 43→    ) -> String {
 44→        format!(
 45→            "{specialist_prompt}\n\n\
 46→             ## Code Under Review\n\n\
 47→             ```rust\n\
 48→             {code}\n\
 49→             ```\n\n\
 50→             ## Context\n\n\
 51→             {context}\n\n\
 52→             ## Output Format\n\n\
 53→             Respond with a JSON object containing:\n\
 54→             - \"verdict\": one of \"pass\", \"warn\", or \"fail\"\n\
 55→             - \"findings\": array of finding objects"
 56→        )
 57→    }
 58→
 59→    /// Build a CLI command for inspection without executing it.
 60→    pub fn build_command(&self, prompt: &str) -> ConstructedCommand {
 61→        ConstructedCommand {
 62→            program: self.claude_cmd.clone(),
 63→            args: vec![
 64→                "-p".to_string(),
 65→                prompt.to_string(),
 66→                "--output-format".to_string(),
 67→                "json".to_string(),
 68→                "--print".to_string(),
 69→            ],
 70→        }
 71→    }
 72→
 73→    /// Parse raw CLI output into a structured `BenchmarkResult`.
 74→    ///
 75→    /// Handles four formats:
 76→    /// 1. Direct JSON: `{"verdict": "...", "findings": [...]}`
 77→    /// 2. Wrapped JSON: `{"result": "{\"verdict\": ...}"}`
 78→    /// 3. Markdown-wrapped JSON: ````json\n{...}\n````
 79→    /// 4. Unparseable: returns error with raw output preserved
 80→    pub fn parse_output(&self, case_name: &str, raw_output: &str) -> BenchmarkResult {
 81→        let trimmed = raw_output.trim();
 82→
 83→        if trimmed.is_empty() {
 84→            return BenchmarkResult {
 85→                case_name: case_name.to_string(),
 86→                verdict: String::new(),
 87→                findings: vec![],
 88→                raw_output: raw_output.to_string(),
 89→                error: Some("Empty output from Claude CLI".to_string()),
 90→            };
 91→        }
 92→
 93→        // Try direct JSON parse
 94→        if let Some(result) = self.try_parse_direct(case_name, trimmed, raw_output) {
 95→            return result;
 96→        }
 97→
 98→        // Try wrapped JSON ({"result": "..."})
 99→        if let Some(result) = self.try_parse_wrapped(case_name, trimmed, raw_output) {
100→            return result;
101→        }
102→
103→        // Try markdown-wrapped JSON (```json ... ```)
104→        if let Some(result) = self.try_parse_markdown(case_name, trimmed, raw_output) {
105→            return result;
106→        }
107→
108→        // Unparseable fallback
109→        BenchmarkResult {
110→            case_name: case_name.to_string(),
111→            verdict: String::new(),
112→            findings: vec![],
113→            raw_output: raw_output.to_string(),
114→            error: Some(format!("Failed to parse output as JSON for case '{case_name}'")),
115→        }
116→    }
117→
118→    /// Attempt to parse as direct JSON with verdict/findings fields.
119→    fn try_parse_direct(
120→        &self,
121→        case_name: &str,
122→        trimmed: &str,
123→        raw_output: &str,
124→    ) -> Option<BenchmarkResult> {
125→        let parsed: serde_json::Value = serde_json::from_str(trimmed).ok()?;
126→        self.extract_result(case_name, &parsed, raw_output)
127→    }
128→
129→    /// Attempt to parse as wrapped JSON where the result field contains an escaped JSON string.
130→    fn try_parse_wrapped(
131→        &self,
132→        case_name: &str,
133→        trimmed: &str,
134→        raw_output: &str,
135→    ) -> Option<BenchmarkResult> {
136→        let outer: serde_json::Value = serde_json::from_str(trimmed).ok()?;
137→        let inner_str = outer.get("result")?.as_str()?;
138→        let inner: serde_json::Value = serde_json::from_str(inner_str).ok()?;
139→        self.extract_result(case_name, &inner, raw_output)
140→    }
141→
142→    /// Attempt to extract JSON from a markdown code block.
143→    fn try_parse_markdown(
144→        &self,
145→        case_name: &str,
146→        trimmed: &str,
147→        raw_output: &str,
148→    ) -> Option<BenchmarkResult> {
149→        let start = trimmed.find("```json\n")? + "```json\n".len();
150→        let end = trimmed[start..].find("```")? + start;
151→        let json_str = trimmed[start..end].trim();
152→        let parsed: serde_json::Value = serde_json::from_str(json_str).ok()?;
153→        self.extract_result(case_name, &parsed, raw_output)
154→    }
155→
156→    /// Extract verdict and findings from a parsed JSON value.
157→    fn extract_result(
158→        &self,
159→        case_name: &str,
160→        value: &serde_json::Value,
161→        raw_output: &str,
162→    ) -> Option<BenchmarkResult> {
163→        let verdict = value.get("verdict")?.as_str()?.to_string();
164→
165→        let findings = value
166→            .get("findings")
167→            .and_then(|f| f.as_array())
168→            .map(|arr| {
169→                arr.iter()
170→                    .filter_map(|item| serde_json::from_value::<Finding>(item.clone()).ok())
171→                    .collect()
172→            })
173→            .unwrap_or_default();
174→
175→        Some(BenchmarkResult {
176→            case_name: case_name.to_string(),
177→            verdict,
178→            findings,
179→            raw_output: raw_output.to_string(),
180→            error: None,
181→        })
182→    }
183→
184→    /// Run a specialist prompt against a benchmark case via the Claude CLI.
185→    pub async fn run(
186→        &self,
187→        case: &BenchmarkCase,
188→        specialist_prompt: &str,
189→    ) -> Result<BenchmarkResult> {
190→        let prompt = self.build_review_prompt(specialist_prompt, &case.code, &case.context);
191→        let cmd = self.build_command(&prompt);
192→
193→        let output = tokio::process::Command::new(&cmd.program)
194→            .args(&cmd.args)
195→            .output()
196→            .await
197→            .with_context(|| {
198→                format!(
199→                    "Failed to run {} for case '{}'",
200→                    self.claude_cmd, case.name
201→                )
202→            })?;
203→
204→        let raw_output = String::from_utf8_lossy(&output.stdout).to_string();
205→        Ok(self.parse_output(&case.name, &raw_output))
206→    }
207→}
208→
209→#[cfg(test)]
210→mod tests {
211→    use super::*;
212→
213→    fn make_runner() -> BenchmarkRunner {
214→        BenchmarkRunner::new("claude".to_string())
215→    }
216→
217→    // --- BenchmarkRunner::new ---
218→
219→    #[test]
220→    fn test_new_stores_claude_cmd() {
221→        let runner = BenchmarkRunner::new("my-claude".to_string());
222→        assert_eq!(runner.claude_cmd, "my-claude");
223→    }
224→
225→    // --- build_command ---
226→
227→    #[test]
228→    fn test_build_command_returns_correct_program_and_args() {
229→        let runner = make_runner();
230→        let cmd = runner.build_command("Review this code");
231→
232→        assert_eq!(cmd.program, "claude");
233→        assert_eq!(
234→            cmd.args,
235→            vec!["-p", "Review this code", "--output-format", "json", "--print"]
236→        );
237→    }
238→
239→    #[test]
240→    fn test_build_command_uses_custom_claude_cmd() {
241→        let runner = BenchmarkRunner::new("/usr/local/bin/claude-dev".to_string());
242→        let cmd = runner.build_command("test prompt");
243→
244→        assert_eq!(cmd.program, "/usr/local/bin/claude-dev");
245→    }
246→
247→    // --- build_review_prompt ---
248→
249→    #[test]
250→    fn test_build_review_prompt_includes_all_sections() {
251→        let runner = make_runner();
252→        let prompt = runner.build_review_prompt(
