  1→//! Results TSV logger for autoresearch experiment outcomes.
  2→//!
  3→//! Reads and writes `results.tsv` — the persistent record of all experiment
  4→//! outcomes in tab-separated format. Each row records commit SHA, composite
  5→//! score, recall, precision, actionability, status (keep/discard/error),
  6→//! specialist, and description. Supports append-with-flush for crash safety
  7→//! and reload across sessions for resume support.
  8→
  9→use std::fmt;
 10→use std::fs;
 11→use std::io::Write;
 12→use std::path::{Path, PathBuf};
 13→
 14→use anyhow::{bail, Context, Result};
 15→
 16→/// TSV header line for results files.
 17→const TSV_HEADER: &str =
 18→    "commit\tscore\trecall\tprecision\tactionability\tstatus\tspecialist\tdescription";
 19→
 20→/// Status of an experiment outcome.
 21→#[derive(Debug, Clone, PartialEq, Eq)]
 22→pub enum ExperimentStatus {
 23→    /// Result accepted into the improvement chain.
 24→    Keep,
 25→    /// Result discarded (regression or no improvement).
 26→    Discard,
 27→    /// Experiment failed with an error.
 28→    Error,
 29→}
 30→
 31→impl ExperimentStatus {
 32→    /// Returns the canonical string representation.
 33→    pub fn as_str(&self) -> &'static str {
 34→        match self {
 35→            Self::Keep => "keep",
 36→            Self::Discard => "discard",
 37→            Self::Error => "error",
 38→        }
 39→    }
 40→
 41→    /// Parses a status string, trimming whitespace. Case-insensitive.
 42→    pub fn from_str(s: &str) -> Result<Self> {
 43→        match s.trim().to_lowercase().as_str() {
 44→            "keep" => Ok(Self::Keep),
 45→            "discard" => Ok(Self::Discard),
 46→            "error" => Ok(Self::Error),
 47→            other => bail!("Unknown experiment status: '{}'", other),
 48→        }
 49→    }
 50→}
 51→
 52→impl fmt::Display for ExperimentStatus {
 53→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 54→        f.write_str(self.as_str())
 55→    }
 56→}
 57→
 58→/// A single experiment result row.
 59→#[derive(Debug, Clone, PartialEq)]
 60→pub struct ResultRow {
 61→    /// Git commit SHA for this experiment.
 62→    pub commit: String,
 63→    /// Composite score (0.0–1.0).
 64→    pub score: f64,
 65→    /// Recall metric (0.0–1.0).
 66→    pub recall: f64,
 67→    /// Precision metric (0.0–1.0).
 68→    pub precision: f64,
 69→    /// Actionability metric (0.0–1.0).
 70→    pub actionability: f64,
 71→    /// Whether the result was kept, discarded, or errored.
 72→    pub status: ExperimentStatus,
 73→    /// Which specialist produced this result.
 74→    pub specialist: String,
 75→    /// Human-readable description of the experiment.
 76→    pub description: String,
 77→}
 78→
 79→impl ResultRow {
 80→    /// Serializes this row to a TSV line (no trailing newline).
 81→    pub fn to_tsv_line(&self) -> String {
 82→        format!(
 83→            "{}\t{:.4}\t{:.4}\t{:.4}\t{:.4}\t{}\t{}\t{}",
 84→            self.commit,
 85→            self.score,
 86→            self.recall,
 87→            self.precision,
 88→            self.actionability,
 89→            self.status.as_str(),
 90→            self.specialist,
 91→            self.description,
 92→        )
 93→    }
 94→
 95→    /// Parses a TSV line into a `ResultRow`.
 96→    ///
 97→    /// Expects at least 8 tab-separated fields. If more than 8 fields exist,
 98→    /// fields 8+ are joined with tabs and treated as part of the description.
 99→    pub fn from_tsv_line(line: &str) -> Result<Self> {
100→        let fields: Vec<&str> = line.split('\t').collect();
101→        if fields.len() < 8 {
102→            bail!(
103→                "Expected 8 tab-separated fields, got {}: '{}'",
104→                fields.len(),
105→                line
106→            );
107→        }
108→        Ok(Self {
109→            commit: fields[0].to_string(),
110→            score: fields[1]
111→                .parse()
112→                .with_context(|| format!("invalid score: '{}'", fields[1]))?,
113→            recall: fields[2]
114→                .parse()
115→                .with_context(|| format!("invalid recall: '{}'", fields[2]))?,
116→            precision: fields[3]
117→                .parse()
118→                .with_context(|| format!("invalid precision: '{}'", fields[3]))?,
119→            actionability: fields[4]
120→                .parse()
121→                .with_context(|| format!("invalid actionability: '{}'", fields[4]))?,
122→            status: ExperimentStatus::from_str(fields[5])?,
123→            specialist: fields[6].to_string(),
124→            description: fields[7..].join("\t"),
125→        })
126→    }
127→}
128→
129→/// File-backed TSV manager for experiment results.
130→///
131→/// Provides query methods and append-with-flush for crash safety.
132→/// Data survives open/close cycles for resume support.
133→pub struct ResultsLog {
134→    path: PathBuf,
135→    rows: Vec<ResultRow>,
136→}
137→
138→impl ResultsLog {
139→    /// Opens a results log, loading existing rows from disk if the file exists.
140→    ///
141→    /// If the file does not exist, starts with an empty row set.
142→    pub fn open(path: &Path) -> Result<Self> {
143→        let mut log = Self {
144→            path: path.to_path_buf(),
145→            rows: Vec::new(),
146→        };
147→        if path.exists() {
148→            let contents = fs::read_to_string(path)
149→                .with_context(|| format!("failed to read results file: {}", path.display()))?;
150→            for (i, line) in contents.lines().enumerate() {
151→                if i == 0 && line.starts_with("commit\t") {
152→                    continue; // skip header
153→                }
154→                if line.trim().is_empty() {
155→                    continue;
156→                }
157→                let row = ResultRow::from_tsv_line(line)
158→                    .with_context(|| format!("failed to parse line {}", i + 1))?;
159→                log.rows.push(row);
160→            }
161→        }
162→        Ok(log)
163→    }
164→
165→    /// Appends a row and immediately flushes to disk for crash safety.
166→    pub fn append(&mut self, row: ResultRow) -> Result<()> {
167→        self.rows.push(row);
168→        self.save()
169→    }
170→
171→    /// Writes all rows to disk, overwriting the file.
172→    pub fn save(&self) -> Result<()> {
173→        let mut file = fs::File::create(&self.path)
174→            .with_context(|| format!("failed to create results file: {}", self.path.display()))?;
175→        writeln!(file, "{}", TSV_HEADER)?;
176→        for row in &self.rows {
177→            writeln!(file, "{}", row.to_tsv_line())?;
178→        }
179→        file.flush()?;
180→        Ok(())
181→    }
182→
183→    /// Returns a slice of all rows.
184→    pub fn rows(&self) -> &[ResultRow] {
185→        &self.rows
186→    }
187→
188→    /// Total number of experiment rows.
189→    pub fn total_experiments(&self) -> usize {
190→        self.rows.len()
191→    }
192→
193→    /// Counts rows matching the given status.
194→    pub fn count_by_status(&self, status: &ExperimentStatus) -> usize {
195→        self.rows.iter().filter(|r| r.status == *status).count()
196→    }
197→
198→    /// Returns the best (highest) score for a specialist among Keep rows only.
199→    pub fn best_score_for(&self, specialist: &str) -> Option<f64> {
200→        self.rows
201→            .iter()
202→            .filter(|r| r.specialist == specialist && r.status == ExperimentStatus::Keep)
203→            .map(|r| r.score)
204→            .fold(None, |max, score| {
205→                Some(max.map_or(score, |m: f64| m.max(score)))
206→            })
207→    }
208→
209→    /// Returns the last `n` rows (or fewer if not enough rows exist).
210→    pub fn last_n(&self, n: usize) -> &[ResultRow] {
211→        let start = self.rows.len().saturating_sub(n);
212→        &self.rows[start..]
213→    }
214→
215→    /// Produces a human-readable summary suitable for LLM context.
216→    pub fn history_summary(&self) -> String {
217→        let total = self.total_experiments();
218→        let keeps = self.count_by_status(&ExperimentStatus::Keep);
219→        let discards = self.count_by_status(&ExperimentStatus::Discard);
220→        let errors = self.count_by_status(&ExperimentStatus::Error);
221→        format!(
222→            "Experiments: {} total ({} keep, {} discard, {} error)",
223→            total, keeps, discards, errors
224→        )
225→    }
226→}
