//! Results TSV logger for autoresearch experiment outcomes.
//!
//! Reads and writes `results.tsv` — the persistent record of all experiment
//! outcomes in tab-separated format. Each row records commit SHA, composite
//! score, recall, precision, actionability, status (keep/discard/error),
//! specialist, and description. Supports append-with-flush for crash safety
//! and reload across sessions for resume support.

use std::fmt;
use std::fs;
use std::io::Write;
use std::path::{Path, PathBuf};

use anyhow::{bail, Context, Result};

/// TSV header line for results files.
const TSV_HEADER: &str =
    "commit\tscore\trecall\tprecision\tactionability\tstatus\tspecialist\tdescription";

/// Status of an experiment outcome.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ExperimentStatus {
    /// Result accepted into the improvement chain.
    Keep,
    /// Result discarded (regression or no improvement).
    Discard,
    /// Experiment failed with an error.
    Error,
}

impl ExperimentStatus {
    /// Returns the canonical string representation.
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Keep => "keep",
            Self::Discard => "discard",
            Self::Error => "error",
        }
    }

    /// Parses a status string, trimming whitespace. Case-insensitive.
    pub fn from_str(s: &str) -> Result<Self> {
        match s.trim().to_lowercase().as_str() {
            "keep" => Ok(Self::Keep),
            "discard" => Ok(Self::Discard),
            "error" => Ok(Self::Error),
            other => bail!("Unknown experiment status: '{}'", other),
        }
    }
}

impl fmt::Display for ExperimentStatus {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str(self.as_str())
    }
}

/// A single experiment result row.
#[derive(Debug, Clone, PartialEq)]
pub struct ResultRow {
    /// Git commit SHA for this experiment.
    pub commit: String,
    /// Composite score (0.0–1.0).
    pub score: f64,
    /// Recall metric (0.0–1.0).
    pub recall: f64,
    /// Precision metric (0.0–1.0).
    pub precision: f64,
    /// Actionability metric (0.0–1.0).
    pub actionability: f64,
    /// Whether the result was kept, discarded, or errored.
    pub status: ExperimentStatus,
    /// Which specialist produced this result.
    pub specialist: String,
    /// Human-readable description of the experiment.
    pub description: String,
}

impl ResultRow {
    /// Serializes this row to a TSV line (no trailing newline).
    pub fn to_tsv_line(&self) -> String {
        format!(
            "{}\t{:.4}\t{:.4}\t{:.4}\t{:.4}\t{}\t{}\t{}",
            self.commit,
            self.score,
            self.recall,
            self.precision,
            self.actionability,
            self.status.as_str(),
            self.specialist,
            self.description,
        )
    }

    /// Parses a TSV line into a `ResultRow`.
    ///
    /// Expects at least 8 tab-separated fields. If more than 8 fields exist,
    /// fields 8+ are joined with tabs and treated as part of the description.
    pub fn from_tsv_line(line: &str) -> Result<Self> {
        let fields: Vec<&str> = line.split('\t').collect();
        if fields.len() < 8 {
            bail!(
                "Expected 8 tab-separated fields, got {}: '{}'",
                fields.len(),
                line
            );
        }
        Ok(Self {
            commit: fields[0].to_string(),
            score: fields[1]
                .parse()
                .with_context(|| format!("invalid score: '{}'", fields[1]))?,
            recall: fields[2]
                .parse()
                .with_context(|| format!("invalid recall: '{}'", fields[2]))?,
            precision: fields[3]
                .parse()
                .with_context(|| format!("invalid precision: '{}'", fields[3]))?,
            actionability: fields[4]
                .parse()
                .with_context(|| format!("invalid actionability: '{}'", fields[4]))?,
            status: ExperimentStatus::from_str(fields[5])?,
            specialist: fields[6].to_string(),
            description: fields[7..].join("\t"),
        })
    }
}

/// File-backed TSV manager for experiment results.
///
/// Provides query methods and append-with-flush for crash safety.
/// Data survives open/close cycles for resume support.
pub struct ResultsLog {
    path: PathBuf,
    rows: Vec<ResultRow>,
}

impl ResultsLog {
    /// Opens a results log, loading existing rows from disk if the file exists.
    ///
    /// If the file does not exist, starts with an empty row set.
    pub fn open(path: &Path) -> Result<Self> {
        let mut log = Self {
            path: path.to_path_buf(),
            rows: Vec::new(),
        };
        if path.exists() {
            let contents = fs::read_to_string(path)
                .with_context(|| format!("failed to read results file: {}", path.display()))?;
            for (i, line) in contents.lines().enumerate() {
                if i == 0 && line.starts_with("commit\t") {
                    continue; // skip header
                }
                if line.trim().is_empty() {
                    continue;
                }
                let row = ResultRow::from_tsv_line(line)
                    .with_context(|| format!("failed to parse line {}", i + 1))?;
                log.rows.push(row);
            }
        }
        Ok(log)
    }

    /// Appends a row and immediately flushes to disk for crash safety.
    pub fn append(&mut self, row: ResultRow) -> Result<()> {
        self.rows.push(row);
        self.save()
    }

    /// Writes all rows to disk, overwriting the file.
    pub fn save(&self) -> Result<()> {
        let mut file = fs::File::create(&self.path)
            .with_context(|| format!("failed to create results file: {}", self.path.display()))?;
        writeln!(file, "{}", TSV_HEADER)?;
        for row in &self.rows {
            writeln!(file, "{}", row.to_tsv_line())?;
        }
        file.flush()?;
        Ok(())
    }

    /// Returns a slice of all rows.
    pub fn rows(&self) -> &[ResultRow] {
        &self.rows
    }

    /// Total number of experiment rows.
    pub fn total_experiments(&self) -> usize {
        self.rows.len()
    }

    /// Counts rows matching the given status.
    pub fn count_by_status(&self, status: &ExperimentStatus) -> usize {
        self.rows.iter().filter(|r| r.status == *status).count()
    }

    /// Returns the best (highest) score for a specialist among Keep rows only.
    pub fn best_score_for(&self, specialist: &str) -> Option<f64> {
        self.rows
            .iter()
            .filter(|r| r.specialist == specialist && r.status == ExperimentStatus::Keep)
            .map(|r| r.score)
            .fold(None, |max, score| {
                Some(max.map_or(score, |m: f64| m.max(score)))
            })
    }

    /// Returns the last `n` rows (or fewer if not enough rows exist).
    pub fn last_n(&self, n: usize) -> &[ResultRow] {
        let start = self.rows.len().saturating_sub(n);
        &self.rows[start..]
    }

    /// Produces a human-readable summary suitable for LLM context.
    pub fn history_summary(&self) -> String {
        let total = self.total_experiments();
        let keeps = self.count_by_status(&ExperimentStatus::Keep);
        let discards = self.count_by_status(&ExperimentStatus::Discard);
        let errors = self.count_by_status(&ExperimentStatus::Error);
        format!(
            "Experiments: {} total ({} keep, {} discard, {} error)",
            total, keeps, discards, errors
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // --- Test helper ---

    fn sample_row(
        commit: &str,
        score: f64,
        status: ExperimentStatus,
        specialist: &str,
        desc: &str,
    ) -> ResultRow {
        ResultRow {
            commit: commit.to_string(),
            score,
            recall: score * 0.9,
            precision: score * 1.1,
            actionability: score * 0.8,
            status,
            specialist: specialist.to_string(),
            description: desc.to_string(),
        }
    }

    // --- ExperimentStatus ---

    #[test]
    fn test_status_as_str_keep() {
        assert_eq!(ExperimentStatus::Keep.as_str(), "keep");
    }

    #[test]
    fn test_status_as_str_discard() {
        assert_eq!(ExperimentStatus::Discard.as_str(), "discard");
    }

    #[test]
    fn test_status_as_str_error() {
        assert_eq!(ExperimentStatus::Error.as_str(), "error");
    }

    #[test]
    fn test_status_from_str_valid() {
        assert_eq!(ExperimentStatus::from_str("keep").unwrap(), ExperimentStatus::Keep);
        assert_eq!(ExperimentStatus::from_str("discard").unwrap(), ExperimentStatus::Discard);
        assert_eq!(ExperimentStatus::from_str("error").unwrap(), ExperimentStatus::Error);
    }

    #[test]
    fn test_status_from_str_trims_whitespace() {
        assert_eq!(ExperimentStatus::from_str("  keep  ").unwrap(), ExperimentStatus::Keep);
        assert_eq!(ExperimentStatus::from_str("\tdiscard\n").unwrap(), ExperimentStatus::Discard);
    }

    #[test]
    fn test_status_from_str_case_insensitive() {
        assert_eq!(ExperimentStatus::from_str("KEEP").unwrap(), ExperimentStatus::Keep);
        assert_eq!(ExperimentStatus::from_str("Discard").unwrap(), ExperimentStatus::Discard);
        assert_eq!(ExperimentStatus::from_str("ERROR").unwrap(), ExperimentStatus::Error);
    }

    #[test]
    fn test_status_from_str_invalid() {
        let result = ExperimentStatus::from_str("unknown");
        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("Unknown experiment status"));
    }

    #[test]
    fn test_status_display() {
        assert_eq!(format!("{}", ExperimentStatus::Keep), "keep");
        assert_eq!(format!("{}", ExperimentStatus::Discard), "discard");
        assert_eq!(format!("{}", ExperimentStatus::Error), "error");
    }

    // --- ResultRow::to_tsv_line ---

    #[test]
    fn test_to_tsv_line_format() {
        let row = sample_row("abc1234", 0.75, ExperimentStatus::Keep, "security", "baseline run");
        let line = row.to_tsv_line();
        assert_eq!(
            line,
            "abc1234\t0.7500\t0.6750\t0.8250\t0.6000\tkeep\tsecurity\tbaseline run"
        );
    }

    #[test]
    fn test_to_tsv_line_four_decimal_precision() {
        let row = ResultRow {
            commit: "deadbeef".to_string(),
            score: 0.123456789,
            recall: 0.111111111,
            precision: 0.999999999,
            actionability: 0.555555555,
            status: ExperimentStatus::Discard,
            specialist: "performance".to_string(),
            description: "precision test".to_string(),
        };
        let line = row.to_tsv_line();
        // Verify 4-decimal formatting
        assert!(line.contains("0.1235")); // score rounded
        assert!(line.contains("0.1111")); // recall
        assert!(line.contains("1.0000")); // precision rounded
        assert!(line.contains("0.5556")); // actionability rounded
    }

    // --- ResultRow::from_tsv_line ---

    #[test]
    fn test_from_tsv_line_valid() {
        let line = "abc1234\t0.7500\t0.6750\t0.8250\t0.6000\tkeep\tsecurity\tbaseline run";
        let row = ResultRow::from_tsv_line(line).unwrap();
        assert_eq!(row.commit, "abc1234");
        assert!((row.score - 0.75).abs() < 0.0001);
        assert!((row.recall - 0.675).abs() < 0.0001);
        assert!((row.precision - 0.825).abs() < 0.0001);
        assert!((row.actionability - 0.6).abs() < 0.0001);
        assert_eq!(row.status, ExperimentStatus::Keep);
        assert_eq!(row.specialist, "security");
        assert_eq!(row.description, "baseline run");
    }

    #[test]
    fn test_from_tsv_line_too_few_fields() {
        let line = "abc1234\t0.75\t0.67";
        let result = ResultRow::from_tsv_line(line);
        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("Expected 8"));
    }

    #[test]
    fn test_from_tsv_line_invalid_score() {
        let line = "abc1234\tNOTANUM\t0.67\t0.82\t0.60\tkeep\tsecurity\ttest";
        let result = ResultRow::from_tsv_line(line);
        assert!(result.is_err());
        assert!(result.unwrap_err().to_string().contains("invalid score"));
    }

    #[test]
    fn test_from_tsv_line_description_with_tabs() {
        let line = "abc1234\t0.75\t0.67\t0.82\t0.60\tkeep\tsecurity\tdesc part1\tpart2\tpart3";
        let row = ResultRow::from_tsv_line(line).unwrap();
        assert_eq!(row.description, "desc part1\tpart2\tpart3");
    }

    // --- Roundtrip ---

    #[test]
    fn test_roundtrip_to_from_tsv() {
        let original = sample_row("cafe0123", 0.8765, ExperimentStatus::Keep, "architecture", "roundtrip test");
        let line = original.to_tsv_line();
        let parsed = ResultRow::from_tsv_line(&line).unwrap();

        assert_eq!(parsed.commit, original.commit);
        // Floats may differ slightly due to 4-decimal formatting
        assert!((parsed.score - 0.8765).abs() < 0.0001);
        assert!((parsed.recall - original.recall).abs() < 0.0001);
        assert!((parsed.precision - original.precision).abs() < 0.0001);
        assert!((parsed.actionability - original.actionability).abs() < 0.0001);
        assert_eq!(parsed.status, original.status);
        assert_eq!(parsed.specialist, original.specialist);
        assert_eq!(parsed.description, original.description);
    }

    #[test]
    fn test_roundtrip_all_statuses() {
        for status in [ExperimentStatus::Keep, ExperimentStatus::Discard, ExperimentStatus::Error] {
            let row = sample_row("aaa1111", 0.5, status.clone(), "simplicity", "status test");
            let line = row.to_tsv_line();
            let parsed = ResultRow::from_tsv_line(&line).unwrap();
            assert_eq!(parsed.status, row.status);
        }
    }

    // --- ResultsLog ---

    #[test]
    fn test_open_nonexistent_starts_empty() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");
        let log = ResultsLog::open(&path).unwrap();
        assert_eq!(log.total_experiments(), 0);
        assert!(log.rows().is_empty());
    }

    #[test]
    fn test_append_and_read_back() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        let mut log = ResultsLog::open(&path).unwrap();
        log.append(sample_row("aaa1111", 0.8, ExperimentStatus::Keep, "security", "first"))
            .unwrap();
        log.append(sample_row("bbb2222", 0.6, ExperimentStatus::Discard, "security", "second"))
            .unwrap();

        assert_eq!(log.total_experiments(), 2);
        assert_eq!(log.rows()[0].commit, "aaa1111");
        assert_eq!(log.rows()[1].commit, "bbb2222");
    }

    #[test]
    fn test_data_survives_open_close_cycles() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        // First session: write rows
        {
            let mut log = ResultsLog::open(&path).unwrap();
            log.append(sample_row("aaa1111", 0.8, ExperimentStatus::Keep, "security", "first"))
                .unwrap();
            log.append(sample_row("bbb2222", 0.6, ExperimentStatus::Discard, "performance", "second"))
                .unwrap();
        }

        // Second session: reopen and verify
        {
            let log = ResultsLog::open(&path).unwrap();
            assert_eq!(log.total_experiments(), 2);
            assert_eq!(log.rows()[0].commit, "aaa1111");
            assert_eq!(log.rows()[1].commit, "bbb2222");
            assert_eq!(log.rows()[0].status, ExperimentStatus::Keep);
            assert_eq!(log.rows()[1].status, ExperimentStatus::Discard);
        }
    }

    #[test]
    fn test_count_by_status() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        let mut log = ResultsLog::open(&path).unwrap();
        log.append(sample_row("a", 0.8, ExperimentStatus::Keep, "security", ""))
            .unwrap();
        log.append(sample_row("b", 0.6, ExperimentStatus::Keep, "security", ""))
            .unwrap();
        log.append(sample_row("c", 0.5, ExperimentStatus::Discard, "security", ""))
            .unwrap();
        log.append(sample_row("d", 0.0, ExperimentStatus::Error, "security", ""))
            .unwrap();

        assert_eq!(log.count_by_status(&ExperimentStatus::Keep), 2);
        assert_eq!(log.count_by_status(&ExperimentStatus::Discard), 1);
        assert_eq!(log.count_by_status(&ExperimentStatus::Error), 1);
    }

    #[test]
    fn test_best_score_for_keeps_only() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        let mut log = ResultsLog::open(&path).unwrap();
        log.append(sample_row("a", 0.7, ExperimentStatus::Keep, "security", ""))
            .unwrap();
        log.append(sample_row("b", 0.9, ExperimentStatus::Discard, "security", "high but discarded"))
            .unwrap();
        log.append(sample_row("c", 0.8, ExperimentStatus::Keep, "security", ""))
            .unwrap();
        log.append(sample_row("d", 0.6, ExperimentStatus::Keep, "performance", ""))
            .unwrap();

        // Best for security should be 0.8 (ignores discarded 0.9)
        let best = log.best_score_for("security").unwrap();
        assert!((best - 0.8).abs() < 0.0001);

        // Best for performance
        let best_perf = log.best_score_for("performance").unwrap();
        assert!((best_perf - 0.6).abs() < 0.0001);

        // No results for unknown specialist
        assert!(log.best_score_for("nonexistent").is_none());
    }

    #[test]
    fn test_last_n() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        let mut log = ResultsLog::open(&path).unwrap();
        for i in 0..5 {
            log.append(sample_row(
                &format!("commit{}", i),
                0.5 + (i as f64) * 0.1,
                ExperimentStatus::Keep,
                "security",
                &format!("run {}", i),
            ))
            .unwrap();
        }

        let last3 = log.last_n(3);
        assert_eq!(last3.len(), 3);
        assert_eq!(last3[0].commit, "commit2");
        assert_eq!(last3[1].commit, "commit3");
        assert_eq!(last3[2].commit, "commit4");

        // Requesting more than available returns all
        let all = log.last_n(100);
        assert_eq!(all.len(), 5);
    }

    #[test]
    fn test_history_summary() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        let mut log = ResultsLog::open(&path).unwrap();
        log.append(sample_row("a", 0.8, ExperimentStatus::Keep, "security", ""))
            .unwrap();
        log.append(sample_row("b", 0.5, ExperimentStatus::Discard, "security", ""))
            .unwrap();
        log.append(sample_row("c", 0.0, ExperimentStatus::Error, "security", ""))
            .unwrap();

        let summary = log.history_summary();
        assert_eq!(summary, "Experiments: 3 total (1 keep, 1 discard, 1 error)");
    }

    #[test]
    fn test_append_flushes_to_disk() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("results.tsv");

        let mut log = ResultsLog::open(&path).unwrap();
        log.append(sample_row("abc", 0.75, ExperimentStatus::Keep, "security", "flush test"))
            .unwrap();

        // Read raw file contents to verify it was written
        let contents = std::fs::read_to_string(&path).unwrap();
        assert!(contents.contains("abc"));
        assert!(contents.contains("0.7500"));
        assert!(contents.contains("keep"));
        assert!(contents.contains("flush test"));
        // Verify header is present
        assert!(contents.starts_with("commit\t"));
    }
}

//! Scoring engine for comparing specialist findings against benchmark ground truth.
//!
//! Uses location proximity and keyword overlap to match findings, then computes
//! recall, precision, and weighted composite scores.

use std::collections::HashSet;
use std::fmt;

use forge::autoresearch::benchmarks::{Expected, ExpectedFinding, MustNotFlag};

use super::judge::{ClassificationVerdict, JudgeResult};

/// A finding produced by a specialist agent.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct Finding {
    pub severity: String,
    pub file: String,
    pub line: Option<u32>,
    pub issue: String,
    pub suggestion: String,
}

/// Composite score for a specialist's performance on benchmarks.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct SpecialistScore {
    pub recall: f64,
    pub precision: f64,
    pub actionability: f64,
    pub composite: f64,
}

impl fmt::Display for SpecialistScore {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            f,
            "recall={:.1}% precision={:.1}% actionability={:.1}% composite={:.1}%",
            self.recall * 100.0,
            self.precision * 100.0,
            self.actionability * 100.0,
            self.composite * 100.0,
        )
    }
}

/// Parsed location from an expected finding's location string.
#[derive(Debug, Clone, PartialEq)]
pub struct ParsedLocation {
    pub file: Option<String>,
    pub start_line: Option<u32>,
    pub end_line: Option<u32>,
}

const LINE_TOLERANCE: u32 = 5;
const MUST_FIND_OVERLAP_THRESHOLD: f64 = 0.50;
const MUST_NOT_FLAG_OVERLAP_THRESHOLD: f64 = 0.60;

const STOP_WORDS: &[&str] = &[
    "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
    "in", "on", "at", "to", "for", "of", "with", "and", "or", "but",
    "not", "this", "that", "it", "its",
];

/// Parse a line range string like `"42-45"` or `"42"` into start/end line numbers.
fn parse_line_range(s: &str) -> (Option<u32>, Option<u32>) {
    if let Some(dash_pos) = s.find('-') {
        let start = s[..dash_pos].parse::<u32>().ok();
        let end = s[dash_pos + 1..].parse::<u32>().ok();
        (start, end)
    } else {
        let line = s.parse::<u32>().ok();
        (line, line)
    }
}

/// Parse a location string like `"code.rs:42-45"`, `"code.rs:42"`, `"line 42-45"`,
/// `"line 42"`, or `""` into a [`ParsedLocation`].
pub fn parse_location(location: &str) -> ParsedLocation {
    let location = location.trim();
    if location.is_empty() {
        return ParsedLocation {
            file: None,
            start_line: None,
            end_line: None,
        };
    }

    // "line 42-45" or "line 42"
    if let Some(line_part) = location.strip_prefix("line ") {
        let (start, end) = parse_line_range(line_part);
        return ParsedLocation {
            file: None,
            start_line: start,
            end_line: end,
        };
    }

    // "file.rs:42-45" or "file.rs:42"
    if let Some(colon_pos) = location.rfind(':') {
        let file = &location[..colon_pos];
        let line_part = &location[colon_pos + 1..];
        let (start, end) = parse_line_range(line_part);
        if start.is_some() {
            return ParsedLocation {
                file: Some(file.to_string()),
                start_line: start,
                end_line: end,
            };
        }
    }

    // Bare filename
    ParsedLocation {
        file: Some(location.to_string()),
        start_line: None,
        end_line: None,
    }
}

/// Tokenize a string: lowercase, split on non-alphanumeric, remove stop words.
fn tokenize(s: &str) -> Vec<String> {
    s.to_lowercase()
        .split(|c: char| !c.is_alphanumeric())
        .filter(|w| !w.is_empty())
        .filter(|w| !STOP_WORDS.contains(w))
        .map(|w| w.to_string())
        .collect()
}

/// Compute keyword overlap between an expected description and a finding description.
///
/// Returns `intersection_count / expected_token_count`, or `0.0` if the expected
/// string has zero non-stop tokens.
pub fn keyword_overlap(expected_desc: &str, finding_desc: &str) -> f64 {
    let expected_tokens: HashSet<String> = tokenize(expected_desc).into_iter().collect();
    if expected_tokens.is_empty() {
        return 0.0;
    }
    let finding_tokens: HashSet<String> = tokenize(finding_desc).into_iter().collect();
    let intersection = expected_tokens.intersection(&finding_tokens).count();
    intersection as f64 / expected_tokens.len() as f64
}

/// Check if a finding's file and line match a parsed location within [`LINE_TOLERANCE`].
fn location_matches(finding: &Finding, loc: &ParsedLocation) -> bool {
    if let Some(ref expected_file) = loc.file
        && finding.file != *expected_file
    {
        return false;
    }
    if let (Some(start), Some(end)) = (loc.start_line, loc.end_line) {
        match finding.line {
            Some(finding_line) => {
                let range_start = start.saturating_sub(LINE_TOLERANCE);
                let range_end = end.saturating_add(LINE_TOLERANCE);
                if finding_line < range_start || finding_line > range_end {
                    return false;
                }
            }
            None => return false,
        }
    }
    true
}

/// Matches specialist findings against benchmark ground truth.
pub struct FindingMatcher;

impl FindingMatcher {
    /// Check if a finding matches an expected finding using location proximity
    /// (±5 lines) AND keyword overlap (>50%). Both must pass when location is present.
    pub fn matches_expected(finding: &Finding, expected: &ExpectedFinding) -> bool {
        let loc = parse_location(&expected.location);
        let has_location = loc.file.is_some() || loc.start_line.is_some();

        let overlap = keyword_overlap(&expected.description, &finding.issue);
        let keyword_match = overlap > MUST_FIND_OVERLAP_THRESHOLD;

        if has_location {
            location_matches(finding, &loc) && keyword_match
        } else {
            keyword_match
        }
    }

    /// Check if a finding matches a must-not-flag entry using keyword overlap (>60%)
    /// OR location match. Either condition triggers a match.
    pub fn matches_must_not_flag(finding: &Finding, must_not: &MustNotFlag) -> bool {
        let overlap = keyword_overlap(&must_not.description, &finding.issue);
        if overlap > MUST_NOT_FLAG_OVERLAP_THRESHOLD {
            return true;
        }

        if let Some(ref loc_str) = must_not.location {
            let loc = parse_location(loc_str);
            if location_matches(finding, &loc) {
                return true;
            }
        }

        false
    }

    /// Count how many findings match at least one must_not_flag entry.
    pub fn count_must_not_flag_hits(
        findings: &[Finding],
        must_not_flag: &[MustNotFlag],
    ) -> usize {
        findings
            .iter()
            .filter(|f| {
                must_not_flag
                    .iter()
                    .any(|mnf| Self::matches_must_not_flag(f, mnf))
            })
            .count()
    }

    /// Identify novel findings: those that match neither any must_find nor any
    /// must_not_flag entry. Returns a set of finding indices.
    pub fn identify_novel_findings(
        findings: &[Finding],
        expected: &Expected,
    ) -> HashSet<usize> {
        findings
            .iter()
            .enumerate()
            .filter(|(_, f)| {
                let matches_must_find = expected
                    .must_find
                    .iter()
                    .any(|ef| Self::matches_expected(f, ef));
                let matches_must_not = expected
                    .must_not_flag
                    .iter()
                    .any(|mnf| Self::matches_must_not_flag(f, mnf));
                !matches_must_find && !matches_must_not
            })
            .map(|(i, _)| i)
            .collect()
    }
}

/// Computes recall, precision, and composite scores.
pub struct Scorer;

impl Scorer {
    /// Score specialist findings against expected outcomes.
    ///
    /// - `recall` = matched_must_finds / total_must_finds (0 must_finds => 1.0)
    /// - `precision` = 1.0 - false_positives / total_findings (0 findings => 1.0)
    /// - `composite` = 0.4 * recall + 0.3 * precision + 0.3 * actionability
    ///
    /// When `judge_result` is `Some`, actionability is the average of the judge's
    /// actionability scores, and novel findings classified as false_positive reduce
    /// precision. When `None`, actionability defaults to 0.5 and novel findings are
    /// assumed true_positive.
    pub fn score(
        findings: &[Finding],
        expected: &Expected,
        judge_result: Option<&JudgeResult>,
    ) -> SpecialistScore {
        let total_must_finds = expected.must_find.len();
        let matched = expected
            .must_find
            .iter()
            .filter(|ef| {
                findings
                    .iter()
                    .any(|f| FindingMatcher::matches_expected(f, ef))
            })
            .count();
        let recall = if total_must_finds == 0 {
            1.0
        } else {
            matched as f64 / total_must_finds as f64
        };

        let precision =
            Self::compute_precision_with_judge(findings, expected, judge_result);

        let actionability = match judge_result {
            Some(jr) if !jr.actionability_scores.is_empty() => {
                let sum: f64 = jr.actionability_scores.iter().map(|s| s.score).sum();
                sum / jr.actionability_scores.len() as f64
            }
            _ => 0.5,
        };

        let composite = 0.4 * recall + 0.3 * precision + 0.3 * actionability;

        SpecialistScore {
            recall,
            precision,
            actionability,
            composite,
        }
    }

    /// Compute precision accounting for judge classifications of novel findings.
    ///
    /// False positives come from two sources:
    /// 1. must_not_flag hits (always counted, regardless of judge)
    /// 2. Novel findings classified as false_positive by the judge (only when judge present)
    ///
    fn compute_precision_with_judge(
        findings: &[Finding],
        expected: &Expected,
        judge_result: Option<&JudgeResult>,
    ) -> f64 {
        let total_findings = findings.len();
        if total_findings == 0 {
            return 1.0;
        }

        let must_not_flag_fps =
            FindingMatcher::count_must_not_flag_hits(findings, &expected.must_not_flag);

        let judge_fps = match judge_result {
            Some(jr) => {
                let novel_indices = FindingMatcher::identify_novel_findings(findings, expected);
                let novel_finding_ids: HashSet<String> =
                    novel_indices.iter().map(|i| i.to_string()).collect();
                jr.classifications
                    .iter()
                    .filter(|c| {
                        novel_finding_ids.contains(&c.finding_id)
                            && c.verdict == ClassificationVerdict::FalsePositive
                    })
                    .count()
            }
            None => 0,
        };

        let total_fps = must_not_flag_fps + judge_fps;
        let precision = 1.0 - (total_fps as f64 / total_findings as f64);
        precision.max(0.0)
    }
}

