    #[test]
    fn test_must_not_flag_always_fp_regardless_of_judge() {
        let expected = Expected {
            must_find: vec![],
            must_not_flag: vec![MustNotFlag {
                id: "fp-1".into(),
                description: "COALESCE MAX position is valid SQL pattern".into(),
