  1→//! Cross-model judge module that invokes GPT 5.4 via Codex CLI to classify
  2→//! review findings as true_positive/false_positive and rate fix actionability.
  3→
  4→#![allow(dead_code)] // Items will be used by future autoresearch command phases.
  5→
  6→use anyhow::{Context, Result};
  7→use serde::{Deserialize, Serialize};
  8→
  9→// ---------------------------------------------------------------------------
 10→// Types
 11→// ---------------------------------------------------------------------------
 12→
 13→/// Verdict for a single finding classification.
 14→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
 15→#[serde(rename_all = "snake_case")]
 16→pub enum ClassificationVerdict {
 17→    TruePositive,
 18→    FalsePositive,
 19→}
 20→
 21→/// Classification of a single finding.
 22→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 23→pub struct Classification {
 24→    pub finding_id: String,
 25→    pub verdict: ClassificationVerdict,
 26→}
 27→
 28→/// Actionability score for a single finding.
 29→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 30→pub struct ActionabilityScore {
 31→    pub finding_id: String,
 32→    pub score: f64,
 33→}
 34→
 35→/// Result returned by the judge containing classifications and actionability scores.
 36→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 37→pub struct JudgeResult {
 38→    pub classifications: Vec<Classification>,
 39→    pub actionability_scores: Vec<ActionabilityScore>,
 40→}
 41→
 42→impl JudgeResult {
 43→    /// Create a safe fallback result: all findings classified as true_positive
 44→    /// with 0.5 actionability.
 45→    pub fn fallback(finding_ids: &[String]) -> Self {
 46→        Self {
 47→            classifications: finding_ids
 48→                .iter()
 49→                .map(|id| Classification {
 50→                    finding_id: id.clone(),
 51→                    verdict: ClassificationVerdict::TruePositive,
 52→                })
 53→                .collect(),
 54→            actionability_scores: finding_ids
 55→                .iter()
 56→                .map(|id| ActionabilityScore {
 57→                    finding_id: id.clone(),
 58→                    score: 0.5,
 59→                })
 60→                .collect(),
 61→        }
 62→    }
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Prompt Builder
 67→// ---------------------------------------------------------------------------
 68→
 69→const JUDGE_PROMPT_TEMPLATE: &str = r#"## Code Under Review
 70→```
 71→{code_sample}
 72→```
 73→
 74→## Ground Truth
 75→```json
 76→{expected_json}
 77→```
 78→
 79→## Specialist Output
 80→```json
 81→{specialist_findings_json}
 82→```
 83→
 84→## Tasks
 85→1. For each finding in the Specialist Output, classify it as `true_positive` or `false_positive` by comparing against the Ground Truth.
 86→2. For each finding, rate the actionability of the suggested fix on a scale of 0.0 to 1.0, where 0.0 means "no actionable fix provided" and 1.0 means "immediately actionable with clear steps".
 87→
 88→## Output
 89→Respond with JSON only. Use this exact schema:
 90→```json
 91→{
 92→  "classifications": [
 93→    {"finding_id": "<id>", "verdict": "true_positive|false_positive"}
 94→  ],
 95→  "actionability_scores": [
 96→    {"finding_id": "<id>", "score": 0.0}
 97→  ]
 98→}
 99→```"#;
100→
101→/// Build the judge prompt by interpolating code, expected JSON, and specialist findings.
102→pub fn build_judge_prompt(
103→    code_sample: &str,
104→    expected_json: &str,
105→    specialist_findings_json: &str,
106→) -> String {
107→    JUDGE_PROMPT_TEMPLATE
108→        .replace("{code_sample}", code_sample)
109→        .replace("{expected_json}", expected_json)
110→        .replace("{specialist_findings_json}", specialist_findings_json)
111→}
112→
113→// ---------------------------------------------------------------------------
114→// Response Parser
115→// ---------------------------------------------------------------------------
116→
117→/// Parse a JSON response from the judge into a `JudgeResult`.
118→///
119→/// Actionability scores are clamped to \[0.0, 1.0\].
120→pub fn parse_judge_response(json_str: &str) -> Result<JudgeResult> {
121→    let mut result: JudgeResult =
122→        serde_json::from_str(json_str).context("failed to parse judge response JSON")?;
123→    for score in &mut result.actionability_scores {
124→        score.score = score.score.clamp(0.0, 1.0);
125→    }
126→    Ok(result)
127→}
128→
129→/// Parse a judge response with fallback: returns `JudgeResult::fallback()` on any failure.
130→pub fn parse_judge_response_with_fallback(json_str: &str, finding_ids: &[String]) -> JudgeResult {
131→    match parse_judge_response(json_str) {
132→        Ok(result) => result,
133→        Err(_) => JudgeResult::fallback(finding_ids),
134→    }
135→}
136→
137→// ---------------------------------------------------------------------------
138→// Command Executor
139→// ---------------------------------------------------------------------------
140→
141→/// Trait for executing external commands, enabling mock injection in tests.
142→#[async_trait::async_trait]
143→pub trait CommandExecutor: Send + Sync {
144→    /// Execute a command with the given arguments and return stdout as a string.
145→    async fn execute(&self, cmd: &str, args: &[String]) -> Result<String>;
146→}
147→
148→/// Production executor using `tokio::process::Command`.
149→pub struct TokioExecutor;
150→
151→#[async_trait::async_trait]
152→impl CommandExecutor for TokioExecutor {
153→    async fn execute(&self, cmd: &str, args: &[String]) -> Result<String> {
154→        let output = tokio::process::Command::new(cmd)
155→            .args(args)
156→            .output()
157→            .await
158→            .with_context(|| format!("failed to execute command: {cmd}"))?;
159→
160→        if !output.status.success() {
161→            let stderr = String::from_utf8_lossy(&output.stderr);
162→            anyhow::bail!("command failed (exit {}): {}", output.status, stderr);
163→        }
164→
165→        String::from_utf8(output.stdout).context("command output was not valid UTF-8")
166→    }
167→}
168→
169→// ---------------------------------------------------------------------------
170→// Judge
171→// ---------------------------------------------------------------------------
172→
173→/// Cross-model judge that invokes GPT 5.4 via Codex CLI.
174→pub struct Judge<E: CommandExecutor = TokioExecutor> {
175→    codex_cmd: String,
176→    model: String,
177→    executor: E,
178→}
179→
180→impl Judge<TokioExecutor> {
181→    /// Create a new judge with the default `TokioExecutor`.
182→    pub fn new() -> Self {
183→        Self {
184→            codex_cmd: "codex".to_string(),
185→            model: "gpt-5.4-xhigh".to_string(),
186→            executor: TokioExecutor,
187→        }
188→    }
189→}
190→
191→impl<E: CommandExecutor> Judge<E> {
192→    /// Create a judge with a custom executor (for testing).
193→    pub fn with_executor(executor: E) -> Self {
194→        Self {
195→            codex_cmd: "codex".to_string(),
196→            model: "gpt-5.4-xhigh".to_string(),
197→            executor,
